import type { FC } from 'react';
import React from 'react';
import { useCallback } from 'react';
import { getActions } from '../../../global';

import type { AgentSelectedMessage } from '../agent/types';

import buildClassName from '../../../util/buildClassName';

import styles from './SelectedMessagesBanner.module.scss';

type OwnProps = {
  selectedMessages: AgentSelectedMessage[];
};

const getPreviewContent = (message: AgentSelectedMessage) => {
  if (message.selectedText?.trim()) {
    return message.selectedText;
  }

  if (message.content?.trim()) {
    return message.content;
  }

  switch (message.messageType) {
    case 'image':
      return '[Photo]';
    case 'video':
      return '[Video]';
    case 'audio':
      return '[Audio]';
    case 'document':
      return '[Document]';
    case 'text':
    default:
      return '[Message]';
  }
};

const SelectedMessagesBanner: FC<OwnProps> = ({ selectedMessages }) => {
  const { clearChatAISelectedMessages } = getActions();

  const handleClearSelectedMessages = useCallback(() => {
    clearChatAISelectedMessages({});
  }, [clearChatAISelectedMessages]);

  if (!selectedMessages || selectedMessages.length === 0) {
    return undefined;
  }

  const message = selectedMessages[0];
  const previewContent = getPreviewContent(message);
  const truncatedContent = previewContent.length > 100
    ? `${previewContent.substring(0, 100)}...`
    : previewContent;

  return (
    <div className={buildClassName(styles.banner, 'selected-messages-banner')}>
      <div className={styles.content}>
        <div className={styles.label}>
          Selected Message
          {selectedMessages.length > 1 && ` (+${selectedMessages.length - 1} more)`}
        </div>
        <div className={styles.messagePreview}>
          {message.senderName && (
            <span className={styles.senderName}>
              {message.senderName}
              :
              {' '}
            </span>
          )}
          <span className={styles.text}>{truncatedContent}</span>
        </div>
      </div>
      <button
        color="translucent"
        onClick={handleClearSelectedMessages}
        className={styles.closeButton}
      >
        <i className="icon icon-close" />
      </button>
    </div>
  );
};

export default SelectedMessagesBanner;
